// Export all DataTables and prepare for GitHub backup
const API_KEY = $vars.N8N_INTERNAL_API_KEY;
const N8N_BASE = $vars.N8N_HOST + '/api/v1';

const TABLES = [
  { id: 'IUOPfsksOPoFG7gV', name: 'tenant_auth' },
  { id: 'mIzRq6aFd01J7MPZ', name: 'capability_catalog' },
  { id: '8uXPK6pD52xG90Y0', name: 'api_registry_v2' },
  { id: ($vars.REGISTRY_V2_ACTION_TABLE_ID || 'UFFQp3heMFys4gPB'), name: 'action_map_v2' },
  { id: 'fSmVnP9qbbqQFAeI', name: 'action_schemas_v1' },
  { id: 'MmlcQmCuoz3M33pD', name: 'health_test_config' },
  { id: 't4tTjYDIkNYdfhdh', name: 'ai_cost_log' },
  { id: 'KSlnbA33PRbFDLne', name: 'credential_expiry' },
  { id: 'wCfdPfENLbe1jvc2', name: 'credential_health' },
  { id: 'FsTInkNFnck4KNrp', name: 'rate_limit_counters' }
];

const date = new Date().toISOString().split('T')[0];
const timestamp = new Date().toISOString();
const allData = {};

for (const table of TABLES) {
  let allRows = [];
  let cursor = '';
  let hasMore = true;
  let pageCount = 0;

  while (hasMore && pageCount < 20) {
    pageCount++;
    try {
      const url = `${N8N_BASE}/data-tables/${table.id}/rows?limit=250${cursor ? '&cursor=' + cursor : ''}`;
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url,
        headers: { 'X-N8N-API-KEY': API_KEY },
        json: true
      });
      allRows = allRows.concat(resp.data || []);
      cursor = resp.nextCursor || '';
      hasMore = !!resp.nextCursor && resp.data && resp.data.length > 0;
    } catch (e) {
      allRows = [{ error: e.message }];
      hasMore = false;
    }
  }

  allData[table.name] = {
    table_id: table.id,
    row_count: allRows.length,
    rows: allRows
  };
}

const files = [
  {
    path: `backups/datatables/datatables-${date}.json`,
    content: JSON.stringify({ timestamp, tables: Object.keys(allData).length, data: allData }, null, 2),
    message: `DataTable backup ${date} — ${Object.entries(allData).map(([k,v]) => `${k}:${v.row_count}`).join(', ')}`
  },
  {
    path: 'backups/datatables/latest.json',
    content: JSON.stringify({ timestamp, tables: Object.keys(allData).length, data: allData }, null, 2),
    message: `Update latest DataTable backup — ${date}`
  }
];

return files.map(f => ({ json: {
  path: f.path,
  message: f.message,
  content_b64: Buffer.from(f.content).toString('base64')
}}));

// Build GitHub PUT body — all data carried in the item, no cross-node references
const shaResp = $input.item.json;
const sha = shaResp && shaResp.sha ? shaResp.sha : null;

// Get the original file data from the SplitInBatches context
const batchItem = $('Process One File').item.json;
const path = batchItem.path;
const content_b64 = batchItem.content_b64;
const message = batchItem.message;

const body = { message, content: content_b64 };
if (sha) body.sha = sha;

return { json: { path, body } };
